#include<bits/stdc++.h>
using namespace std;
stack<int> x;const int MOD=10000;
int ans,b;char c;
int main(void){
	cin>>ans,ans%=MOD;
	x.push(ans);
	while(cin>>c>>b){
		if(c=='*')ans=x.top(),x.pop(),x.push(ans*b%MOD);
		else x.push(b);
	}ans=0;
	while(x.size())ans+=x.top(),ans%=MOD,x.pop();
	cout<<ans;return false;
}
